var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님, 혹시 많이 화나셨나요?","JPN":"レジーナ様、もしや……怒っていますか？","ENG":"Are you angry, Miss Regina?","TWN":"蕾佳娜大人，您很生氣嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네? 제가 그런 표정을 짓고 있었어요?","JPN":"え？　私、そんな顔をしていましたか？","ENG":"Sorry? Did I look angry?","TWN":"什麼？我露出了那種表情嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네. 무척 심란해 보이셔서...... 저희가 괜한 이야기를 드린 걸까요?","JPN":"ええ。とても怖い顔をして……我々は何か余計なことを言いましたか？","ENG":"Yes. You looked very troubled. Was it too much for you to take in?","TWN":"是。因為您看起來很煩躁……是我們說了不該說的話嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 그렇진 않아요. 어머니에 대한 기억 탓이죠.","JPN":"いいえ、大丈夫ですわ。母に関する記憶のせいでしょう。","ENG":"No, it's okay. It's just these memories I have with my mother.","TWN":"不，沒有。是因為想起了有關母親的回憶吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"고향을 떠난 뒤로 이상하리만치 깨끗하게 잊고 지냈는데...... 돌아오고 나서부터 드문드문 떠오르네요.","JPN":"故郷を離れてから、おかしなほどすっかり\\n忘れていましたが……帰って来てから時々思い出してしまって。","ENG":"I thought I lost them all while I was away from home, but I keep having these flashbacks.","TWN":"明明離開故鄉後，我就把這些事情忘得異常地乾淨……但自從回到這裡後，總是不時會想起來呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"정말이지, 싫어도 고향은 고향인가 봐요.","JPN":"本当に、嫌でも故郷は故郷みたいですわ。","ENG":"I guess home is home, no matter how hard I try to forget about it.","TWN":"真是的，就算討厭，故鄉還是故鄉呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"맥크레디 부인은 역대 학회장 중 가장 오랫동안 재임해 온 분이세요.","JPN":"マクレディー夫人は歴代学会長の中でも、最も在任期間の長い方でした。","ENG":"Mrs. MacCready served as the President for the longest time in the Society's history.","TWN":"麥克蕾蒂夫人是歷任學會長中，在任時間最長的一位。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"누구보다 가문과 학회를 아끼셨지만...... 시간이 흐르면서 그 마음이 잘못된 방향으로 엇나가 버렸죠.","JPN":"誰よりもマクレディー家と学会を大切にしていましたが……\\n時が経ち、その気持ちが誤った方向へ膨らんでしまったのです。","ENG":"She cherished her family and the Society more than anyone else, but her enthusiasm eventually led her down the wrong path.","TWN":"她比任何人都要珍惜家族和學會，但是……隨著時間的流逝，這份珍惜也漸漸偏向了錯誤的方向。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어머니를 변호해 주실 필요 없어요.","JPN":"お母様を擁護する必要はありません。","ENG":"You don't have to defend my mother.","TWN":"妳沒必要為母親辯護。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신에게는 미안한 짓이 되었지만...... 저는 영지를 떠나서 다행이었다고 생각해요.","JPN":"あなたには申し訳ありませんでしたが……私は領地を離れて正解だったと思っていますの。","ENG":"I feel sorry for what happened to you, but I'm glad that I left the estate.","TWN":"雖然這麼說不太對得起妳……但我仍然覺得自己離開這裡真是太好了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그대로 머물러 있었다면 어머니처럼 자랐거나, 그전에 죽었거나. 둘 중 하나였겠죠.","JPN":"そのまま留まっていれば、お母様のような人間に\\n育ったか、その前に死んだかのどちらかだったでしょう。","ENG":"If I had stayed, I would have either become just like my mother, or died before I did.","TWN":"如果我留在這裡，我應該就會長大成母親那樣的人，或是在那之前就死掉。只可能是這兩種結局吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하긴 목숨이 위태로운 건 지금도 마찬가지네요.","JPN":"まあ、命が危ういのは今も同じですけどね。","ENG":"But then, look at me. I'm back home, and death doesn't seem to be far anyway.","TWN":"說起來，生命受到威脅這點，現在也是一樣的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그럴 리는 없으니 걱정하지 마세요.","JPN":"そんなはずはありませんから、ご心配なく。","ENG":"You'll be fine, so don't worry.","TWN":"不會有這種事的，請不要擔心。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님은 차기 학회장이시잖아요. 계승식 전까지는 저희가 꼭 지켜 드릴게요.","JPN":"レジーナ様は次期学会長です。継承式までは我々が必ずお守りしますから。","ENG":"You're the next President of the Society. We'll make sure nothing happens to you before the succession ceremony.","TWN":"蕾佳娜大人是下任學會長啊。在繼承儀式結束前，我們一定會保護您的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"말뿐이라도 고맙네요. 계승식만 운운하지 않았으면 더 고마웠을 텐데요.","JPN":"言葉だけでもありがたいですわ。継承式の話さえしなければ、もっとありがたかったと思いますが。","ENG":"Thank you, really. It would have been much nicer if you left the succession ceremony part out.","TWN":"就算妳只是說說，我也很感謝妳。而如果妳沒提到繼承儀式，我會更感謝妳的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"거기 화기애애하게 노닥거리는 두 사람! 여기야!","JPN":"そこの仲良くおしゃべりしてるお二人さん！　ここだよ！","ENG":"Hey, chatterboxes! Over here!","TWN":"在那邊和樂融融，打情罵俏的那兩個！在這裡！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어머니는 찾았나요?","JPN":"母は見つかりましたか？","ENG":"Did you find my mother?","TWN":"找到母親了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그게 말이지, 이 앞에서 흔적이 끊겼더라고.","JPN":"それが、この先で痕跡が途絶えてるんだよね。","ENG":"Well, her trail stops here.","TWN":"這個嘛，痕跡在前面就中斷了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"근처부터 차근차근 수색해 나가야 할 거 같아.","JPN":"近い場所から少しずつ捜索して行った方が良さそう。","ENG":"I'm afraid we'll have to search for another trail from this point on.","TWN":"我們只能在這附近一點一點地慢慢找了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하여간...... 마지막까지 사람을 고생시키네요.","JPN":"まったく……最後まで人を苦労させるのですね。","ENG":"Geez... Even after death, she's giving everyone a hard time.","TWN":"總之……到最後都不讓人輕鬆啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"이 근처라면...... 곤란하네요.","JPN":"この近くだと……困りましたね。","ENG":"No... This can't be good.","TWN":"這附近的話……真是困擾呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭔가 짚이는 게 있나요?","JPN":"何か心当たりでもあるんですか？","ENG":"Do you have any guesses?","TWN":"妳心中有什麼線索了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아이들은 모두 완전한 하나가 되길 원해요.","JPN":"この子たちはみんな、完全体になることを望んでいるんです。","ENG":"By nature, the babies tend to exist as a complete whole.","TWN":"孩子們都希望能成為完全的整體。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그러기 위해 본능적으로 서로를 흡수하려 하죠.","JPN":"そのために、本能的にお互いを吸収しようとするんですよ。","ENG":"They try to absorb each other instinctively.","TWN":"為此，它們在本能上會相互吸收。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하지만 부인의 시신에 남은 아이들은 저희를 흡수할 수 있을 만큼 강하진 않아요.","JPN":"でも、夫人の遺体に残った子たちは我々を吸収できるほど強くありません。","ENG":"But the ones left on Mrs. MacCready aren't strong enough to absorb us.","TWN":"但是，在夫人遺體中留下的孩子們，還沒有強大到能吸收我們。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇다면...... 힘을 키우려고 하겠군요.","JPN":"ならば……力を手に入れようとするでしょうね。","ENG":"Then... they'll want to build up their strength.","TWN":"這樣的話……它們應該會想增強力量吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네. 여기서 가까운 곳에 역대 학회장 분들의 유해를 안치해 놓은 제단이 있답니다.","JPN":"ええ。ここから近い場所に歴代学会長の遺体を安置した祭壇があるんです。","ENG":"Exactly. There's an altar where we keep all the remains of past Presidents near here.","TWN":"沒錯。這裡附近有個安放歷代學會長遺體的祭壇。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"만약 아이들이 그곳을 장악하게 되면 저희만으로는 벅찰 수도 있어요.","JPN":"もしもあの子たちがここを掌握することになれば、我々だけでは手こずることになるかもしれません。","ENG":"If the babies reach there first, we won't be able to stop them on our own.","TWN":"如果孩子們掌握了這個地方，光靠我們可能會無法對付。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"절대 그렇게는 안 돼요. 돌아가신 분들의 시신까지 욕보이게 놔둘 수는 없습니다.","JPN":"絶対にそうはさせません。亡くなった方まで好きなようにさせるわけにはいきませんから。","ENG":"That won't happen. I won't let them disgrace the deceased.","TWN":"絕對不可以。不能讓逝者的遺體都受到污辱。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제단으로 가죠. 더 늦기 전에......","JPN":"祭壇に向かいましょう。手遅れになる前に……","ENG":"Let's go to the altar before it's too—","TWN":"去祭壇吧。趁現在為時不晚……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ESPR_NPC_FEMALE_NULL","text":{"KOREA":"응? 레지나 아냐?","JPN":"あれ？　レジーナ？","ENG":"Hm? Regina?","TWN":"嗯？這不是蕾佳娜嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESPR_NPC_FEMALE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에밀리......?","JPN":"エミリー……？","ENG":"Emily?","TWN":"艾米麗……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"도시에 나가서 산다고 했잖아? 여긴 무슨 일이야?","JPN":"都市に出て暮らしてるって聞きましたが？　どうしてここに？","ENG":"Didn't you say you were moving out to the city? What are you doing here?","TWN":"妳不是說妳要去城市生活嗎？怎麼會在這裡？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESPR_NPC_FEMALE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"ESPR_NPC_FEMALE_NULL","text":{"KOREA":"가끔은 고향에 오고 싶어지잖아. 그 덕분에 못 보던 친구도 만났고.","JPN":"たまには故郷に帰りたくなるじゃない。おかげで、久しぶりの友達にも会えたし。","ENG":"Well, let's say I've gotten a little homesick. And thanks to that, I was able to meet an old friend of mine.","TWN":"偶爾也會想回故鄉嘛。還因此見到了好久不見的朋友。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESPR_NPC_FEMALE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"ESPR_NPC_FEMALE_NULL","text":{"KOREA":"레지나야말로 영지에 무슨 일이야? 예전부터 고향 얘기만 나오면 질색했잖아?","JPN":"レジーナこそ、領地には何の用？　昔から故郷の話をするのも嫌がってたのに。","ENG":"What are you doing here in the estate, Regina? You used to hate it whenever someone tried to talk to you about home.","TWN":"蕾佳娜才是，來這裡有什麼要辦的事情嗎？妳不是從以前開始，光是提到故鄉就很厭惡嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESPR_NPC_FEMALE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"응. 집안에 급한 일이 생기는 바람에......","JPN":"うん。ちょっと家に急用ができて……","ENG":"Yeah, there was a family emergency, so...","TWN":"嗯。因為家裡突然有急事……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESPR_NPC_FEMALE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"스트─라이크! 리벳 선수, 묵직한 직구를 꽂아 버립니다!","JPN":"ストラーイク！　リベット選手のどっしり重い直球が突き刺さりました！","ENG":"Strrrike! Rivet's powerful fastball goes right into the catcher's mitt!","TWN":"好球！里維選手，投出了一記沉重的直球！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"무슨 짓이에요?! 제 고향 친구란 말이에요!","JPN":"何をするんですか！？　故郷の友達なのですよ！","ENG":"What the heck are you doing? She's a friend from home!","TWN":"妳做什麼？！那是我在故鄉的好友啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"더는 못 참겠어! 제정신이 아니어도 정도가 있지!","JPN":"もう我慢できません！　正気じゃないにもほどがありますわ！","ENG":"That's it! I've had enough of your lunacy!","TWN":"我再也受不了了！發瘋也該有個限度吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"진정하세요, 레지나 님. 그건 사람이 아니에요.","JPN":"落ち着いてください、レジーナ様。それは人ではありません。","ENG":"Calm down, Miss Regina. That wasn't your friend.","TWN":"請冷靜一點，蕾佳娜大人。那並不是人類。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"말도 안 되는 소리 말아요! 제가 헛것이라도 봤다는 건가요!","JPN":"馬鹿なことを言わないでください！　私が幻でも見たというのですか！","ENG":"Don’t be absurd! Are you trying to say that I was hallucinating?","TWN":"別胡說八道了！妳是說我看到了幻覺嗎！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델 당신이야말로 두 눈 똑바로 뜨고 봐요! 저 여자가 누굴 쐈는지!","JPN":"エデル、あなたこそしっかり見てください！　彼女が誰を撃ったのか！","ENG":"Open your eyes and look again, Edel! Look who that crazy woman shot!","TWN":"艾瑟兒才是，好好擦亮眼睛看清楚！那個女人到底射中了誰！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"힉......?!","JPN":"ひッ……！？","ENG":"Hic...","TWN":"咿……？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OCTOPUS_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저.... 저 괴물들이...... 어떻게...... 언제 이렇게 많이......","JPN":"あ……あの怪物が……どうして……いつの間にこんなにたくさん……","ENG":"Those... Those monsters... How... When did they...","TWN":"那……那些怪物……怎麼會……什麼時候來了這麼多……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에이, 방금 반갑게 말 걸었던 사람이 왜 그래. 겉모습이 아니라 내면을 봐 주라고.","JPN":"ぷっ、ついさっき嬉しそうに話してたくせに。外見じゃなくて中身を見なきゃ。","ENG":"Come on, you were having a nice chat with them just now. You should look what's inside, not on the outside.","TWN":"哎呀，妳剛才不還開心地在和它聊天嘛，幹嘛這個反應啊。別光看外表，也好好看看內在啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 저 괴물들에게 말을 걸었다고요......? 그럼 제가 본 에밀리가......? ","JPN":"私があの怪物たちと話をしてた……？　つまり、私が見たエミリーは……？ ","ENG":"I talked to those monsters? Then the Emily I just saw... ","TWN":"妳是說我剛才和那些怪物搭話……？那我看到的艾米麗……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"도시 사는 친구랑 이 시간에 숲에서 마주칠 리 없잖아?","JPN":"都市に住んでる友達と、こんな時間に森で出くわすわけないでしょ？","ENG":"Why would your friend who moved to the city wander in a forest at this time of night?","TWN":"妳和那位住在城市的朋友，怎麼可能這個時間會在森林裡相遇啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"정신 차려, 레지나! 함정이야!","JPN":"しっかりして、レジーナ！　罠だよ！","ENG":"Wake up, silly. It's a trap!","TWN":"振作點啊，蕾佳娜！這是陷阱！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};